import React, { useEffect, useState } from 'react';
import {
  Card,
  Row,
  Col,
  Badge,
  Modal,
  Button
} from 'react-bootstrap';
import {
  Store,
  Users,
  ArrowLeft,
  CheckCircle,
  AlertTriangle,
  XCircle
} from 'lucide-react';
import { searchDocuments } from '../api';
import './ComplianceDashboard.css';

/* ===========================
   CONFIG
===========================*/
const MANDATORY_DOCS = [
  'ID Proof',
  'Address Proof',
  'Educational Certificate',
  'Employment Contract'
];

const ComplianceDashboard = () => {
  const [view, setView] = useState('STORE'); // STORE | EMPLOYEE
  const [stores, setStores] = useState([]);
  const [selectedStore, setSelectedStore] = useState(null);
  const [selectedEmployee, setSelectedEmployee] = useState(null);

  useEffect(() => {
    loadDashboardData();
  }, []);

  /* ===========================
     HELPERS
  ===========================*/
  const getStatus = (expiryDate) => {
    if (!expiryDate) return 'valid';
    const days =
      Math.floor(
        (new Date(expiryDate) - new Date()) / (1000 * 60 * 60 * 24)
      );
    if (days <= 0) return 'expired';
    if (days <= 30) return 'expiring';
    return 'valid';
  };

  /* ===========================
     DATA LOAD & PROCESS
  ===========================*/
  const loadDashboardData = async () => {
    const res = await searchDocuments({});
    const docs = res?.data?.data || [];

    const storeMap = {};
    const empMap = {};

    /* --- Step 1: Group documents per employee --- */
    docs.forEach(doc => {
      const status = getStatus(doc.expiryDate);

      if (!empMap[doc.employeeId]) {
        empMap[doc.employeeId] = {
          id: doc.employeeId,
          name: doc.employeeName || 'Unknown',
          store: doc.store || 'Unknown',
          documents: [],
          expiredCount: 0
        };
      }

      empMap[doc.employeeId].documents.push({
        documentType: doc.documentType,
        status
      });

      if (status === 'expired') {
        empMap[doc.employeeId].expiredCount++;
      }
    });

    /* --- Step 2: Calculate missing docs PER EMPLOYEE (FIXED BUG) --- */
    Object.values(empMap).forEach(emp => {
      const uploadedTypes = emp.documents.map(d => d.documentType);

      emp.missingDocs = MANDATORY_DOCS.filter(
        mandatory => !uploadedTypes.includes(mandatory)
      );

      emp.isCompliant =
        emp.missingDocs.length === 0 && emp.expiredCount === 0;

      /* --- Step 3: Group employees per store --- */
      if (!storeMap[emp.store]) {
        storeMap[emp.store] = {
          store: emp.store,
          employees: []
        };
      }

      storeMap[emp.store].employees.push(emp);
    });

    /* --- Step 4: Store compliance = % of compliant employees --- */
    Object.values(storeMap).forEach(store => {
      const totalEmployees = store.employees.length;
      const compliantEmployees = store.employees.filter(
        e => e.isCompliant
      ).length;

      store.compliancePercent = totalEmployees
        ? Math.round((compliantEmployees / totalEmployees) * 100)
        : 0;
    });

    setStores(Object.values(storeMap));
  };

  /* ===========================
     STORE VIEW (LEVEL 1)
  ===========================*/
  if (view === 'STORE') {
    return (
      <div className="compliance-dashboard">
        <h3 className="mb-4">
          <Store className="me-2" size={24} />
          Store Compliance Overview
        </h3>

        <Row className="g-4">
          {stores.map(store => (
            <Col md={4} lg={3} key={store.store}>
              <Card
                className="store-card h-100 text-center"
                onClick={() => {
                  setSelectedStore(store);
                  setView('EMPLOYEE');
                }}
              >
                <Card.Body>
                  <h5>{store.store}</h5>

                  <div className="compliance-circle my-3">
                    {store.compliancePercent}%
                  </div>

                  <small className="text-muted d-block mb-2">
                    % Employees Fully Compliant
                  </small>

                  <Badge
                    bg={
                      store.compliancePercent >= 80
                        ? 'success'
                        : store.compliancePercent >= 50
                        ? 'warning'
                        : 'danger'
                    }
                  >
                    View Employees →
                  </Badge>
                </Card.Body>
              </Card>
            </Col>
          ))}
        </Row>
      </div>
    );
  }

  /* ===========================
     EMPLOYEE VIEW (LEVEL 2)
  ===========================*/
  return (
    <div className="compliance-dashboard">
      <Button
        variant="link"
        className="mb-3"
        onClick={() => setView('STORE')}
      >
        <ArrowLeft size={16} /> Back to Stores
      </Button>

      <h4 className="mb-4">
        <Users className="me-2" size={20} />
        {selectedStore.store} – Employees
      </h4>

      <Row className="g-4">
        {selectedStore.employees
          .sort((a, b) => a.isCompliant - b.isCompliant)
          .map(emp => (
            <Col md={4} lg={3} key={emp.id}>
              <Card
                className={`employee-card h-100 ${
                  emp.isCompliant ? 'border-success' : 'border-danger'
                }`}
                onClick={() => setSelectedEmployee(emp)}
              >
                <Card.Body>
                  <h6>{emp.name}</h6>

                  {emp.isCompliant ? (
                    <Badge bg="success">
                      <CheckCircle size={14} /> Compliant
                    </Badge>
                  ) : (
                    <Badge bg="danger">
                      <AlertTriangle size={14} /> Pending
                    </Badge>
                  )}

                  <div className="mt-2 small">
                    Missing Docs:{' '}
                    <strong>{emp.missingDocs.length}</strong>
                  </div>
                </Card.Body>
              </Card>
            </Col>
          ))}
      </Row>

      {/* ===========================
          EMPLOYEE DETAIL MODAL
      ===========================*/}
      <Modal
        show={!!selectedEmployee}
        onHide={() => setSelectedEmployee(null)}
        centered
      >
        {selectedEmployee && (
          <>
            <Modal.Header closeButton>
              <Modal.Title>{selectedEmployee.name}</Modal.Title>
            </Modal.Header>

            <Modal.Body>
              <h6>Mandatory Documents</h6>

              {MANDATORY_DOCS.map(doc => {
                const uploaded = selectedEmployee.documents.some(
                  d => d.documentType === doc
                );

                return (
                  <div key={doc} className="mb-2">
                    {uploaded ? (
                      <CheckCircle size={16} className="text-success me-2" />
                    ) : (
                      <XCircle size={16} className="text-danger me-2" />
                    )}
                    {doc}
                  </div>
                );
              })}
            </Modal.Body>

            <Modal.Footer>
              <Button onClick={() => setSelectedEmployee(null)}>
                Close
              </Button>
            </Modal.Footer>
          </>
        )}
      </Modal>
    </div>
  );
};

export default ComplianceDashboard;
